import React from "react";
import styled from "styled-components";
import emailjs from "emailjs-com";

import Panel from "./panel";
import Button from "./button";

class ContactPanel extends React.Component {
  constructor(props) {
    super(props);
  }

  handleSubmit = (e) => {
    e.preventDefault();

    emailjs
      .sendForm(
        "service_bp7joj7", // Service ID
        "template_gmn0yg5", // Template ID
        e.target,
        "user_pxUfYL4KJtfRC2tvUcxVC" // User ID
      )
      .then(
        (result) => {
          console.log(result.text);
        },
        (error) => {
          console.log(error.text);
        }
      );
    e.target.reset();
  };

  render() {
    return (
      <Panel color={this.props.colors.panel}>
        <TitleRow>
          <Title color={this.props.colors.heading}>Contact Me</Title>
        </TitleRow>
        <BodyContainer>
          <Form onSubmit={this.handleSubmit}>
            <SenderInfoRow>
              <SenderInfoInput
                type="text"
                placeholder="Your name"
                name="name"
                required
              />
              <SenderInfoInput
                type="email"
                placeholder="Your email"
                name="email"
                required
              />
            </SenderInfoRow>
            <MessageRow>
              <MessageInput
                id="contactMessage"
                type="text"
                placeholder="Want to connect, collaborate, or critique? Send me a message!"
                name="message"
                required
              />
            </MessageRow>
            <SubmitRow>
              <Button
                type="submit"
                value="Submit"
                backgroundColor={this.props.colors.panel}
                borderColor={this.props.colors.button_border}
                textColor={this.props.colors.button_text}
                hoverBackgroundColor={this.props.colors.main}
              >
                Submit
              </Button>
            </SubmitRow>
          </Form>
        </BodyContainer>
      </Panel>
    );
  }
}

export default ContactPanel;

/* START: TITLE */
const TitleRow = styled.div`
  display: flex;
  flex-direction: column;
  margin: 0 2rem;
`;

const Title = styled.h2`
  position: relative;
  display: block;
  margin: 0 3rem;
  text-align: right;
  font-size: 6rem;
  color: ${(props) => props.color};
  line-height: 6rem;
  font-family: sans-serif;
`;
/* END: TITLE */

/* START: BODY */
const BodyContainer = styled.div`
  margin: 2rem 4rem 2rem 4rem;
  display: flex;
  flex-direction: column;
`;

const Form = styled.form`
  display: flex;
  flex-direction: column;
`;

const SenderInfoRow = styled.div``;

const SenderInfoInput = styled.input`
  border-radius: 10px;
  font-size: 1.5rem;

  margin: 0 0 1rem 0;
  padding: 0.5rem;
  border: none;
  outline: none;
  width: 70%;
`;

const MessageRow = styled.div`
  width: 100%;
`;

const MessageInput = styled.textarea`
  padding: 0.5rem;
  margin: 0rem 0;
  width: 100%;
  min-height: 10rem;
  border-radius: 10px;
  font-size: 1.5rem;

  border: none;
  outline: none;
  resize: vertical;
  overflow: hidden;
  box-sizing: border-box;
`;

const SubmitRow = styled.div`
  margin: 1rem 0 0 0;
  padding: 0;
  width: 100%;
`;
/* END: BODY */
